import jwt
from jwt import PyJWTError

class JWTWrapper:
    def __init__(self, secret_key=None, public_key=None):
        self.secret_key = secret_key
        self.public_key = public_key

    def encode(self, payload, algorithm='HS256'):
        if algorithm == 'HS256':
            return jwt.encode(payload, self.secret_key, algorithm=algorithm)
        elif algorithm == 'RS256':
            return jwt.encode(payload, self.public_key, algorithm=algorithm)
        else:
            raise ValueError("Unsupported algorithm")

    def decode(self, token, algorithms):
        try:
            return jwt.decode(token, self.secret_key or self.public_key, algorithms=algorithms)
        except PyJWTError as e:
            raise ValueError("Invalid token") from e

    def verify(self, token, algorithms):
        try:
            payload = self.decode(token, algorithms)
            return True, payload
        except ValueError:
            return False, None

